import { UnionFind } from './UnionFind';

function solve(c, connections, queries) {
    // Initialize Union-Find structure for the grid
    const uf = new UnionFind(c);

    // Process connections to build the grid
    for (const [u, v] of connections) {
        uf.union(u, v);
    }

    // For each node, store the root of its set
    const rootMap = new Array(c + 1).fill(0).map((_, i) => uf.find(i));

    // For each root, store the minimum node in its set
    const minNodeMap = new Map();
    for (let i = 1; i <= c; i++) {
        const root = uf.find(i);
        if (!minNodeMap.has(root)) {
            minNodeMap.set(root, i);
        }
    }

    const result = [];

    // Process queries
    for (const [type, x] of queries) {
        if (type === 1) {
            // Maintenance check query
            if (uf.isOnline(x)) {
                result.push(x);
            } else {
                // Find the root of x
                const root = uf.find(x);
                // Get the minimum node in the root's set
                const minNode = minNodeMap.get(root);
                if (minNode !== undefined) {
                    result.push(minNode);
                } else {
                    result.push(-1);
                }
            }
        } else {
            // Offline query
            uf.offline(x);
        }
    }

    return result;
}

class UnionFind {
    constructor(size) {
        this.parent = [];
        this.rank = [];
        this.online = [];
        this.minNode = [];

        for (let i = 0; i <= size; i++) {
            this.parent[i] = i;
            this.rank[i] = 0;
            this.online[i] = true;
            this.minNode[i] = i;
        }
    }

    find(x) {
        if (this.parent[x] !== x) {
            this.parent[x] = this.find(this.parent[x]);
        }
        return this.parent[x];
    }

    union(x, y) {
        const xRoot = this.find(x);
        const yRoot = this.find(y);

        if (xRoot === yRoot) {
            return;
        }

        if (this.rank[xRoot] < this.rank[yRoot]) {
            this.parent[xRoot] = yRoot;
            this.minNode[yRoot] = Math.min(this.minNode[yRoot], this.minNode[xRoot]);
        } else {
            this.parent[yRoot] = xRoot;
            this.minNode[xRoot] = Math.min(this.minNode[xRoot], this.minNode[yRoot]);
            if (this.rank[xRoot] === this.rank[yRoot]) {
                this.rank[xRoot]++;
            }
        }
    }

    offline(x) {
        this.online[x] = false;
        const root = this.find(x);
        this.minNode[root] = this.minNode[root] === x ? this.minNode[root] : this.minNode[root];
    }

    isOnline(x) {
        return this.online[x];
    }
}

