import "container/heap"

type UnionFind struct {
	parent   []int64
	rank     []int64
	online   []bool
	minNode  []int64
}

func NewUnionFind(size int64) *UnionFind {
	uf := &UnionFind{
		parent:   make([]int64, size+1),
		rank:     make([]int64, size+1),
		online:   make([]bool, size+1),
		minNode:  make([]int64, size+1),
	}
	for i := int64(0); i <= size; i++ {
		uf.parent[i] = i
		uf.rank[i] = 0
		uf.online[i] = true
		uf.minNode[i] = i
	}
	return uf
}

func (uf *UnionFind) find(x int64) int64 {
	if uf.parent[x] != x {
		uf.parent[x] = uf.find(uf.parent[x])
	}
	return uf.parent[x]
}

func (uf *UnionFind) union(x, y int64) {
	xRoot := uf.find(x)
	yRoot := uf.find(y)
	if xRoot == yRoot {
		return
	}
	if uf.rank[xRoot] < uf.rank[yRoot] {
		uf.parent[xRoot] = yRoot
		uf.minNode[yRoot] = min(uf.minNode[yRoot], uf.minNode[xRoot])
	} else {
		uf.parent[yRoot] = xRoot
		uf.minNode[xRoot] = min(uf.minNode[xRoot], uf.minNode[yRoot])
		if uf.rank[xRoot] == uf.rank[yRoot] {
			uf.rank[xRoot]++
		}
	}
}

func (uf *UnionFind) offline(x int64) {
	uf.online[x] = false
	root := uf.find(x)
	if uf.minNode[root] == x {
		uf.minNode[root] = root
	}
}

func (uf *UnionFind) isOnline(x int64) bool {
	return uf.online[x]
}

func min(a, b int64) int64 {
	if a < b {
		return a
	}
	return b
}

func solve(c int64, connections [][]int64, queries [][]int64) []int64 {
	uf := NewUnionFind(c)
	for _, conn := range connections {
		uf.union(conn[0], conn[1])
	}

	// For each node, store the root of its set
	rootMap := make([]int64, c+1)
	for i := int64(1); i <= c; i++ {
		rootMap[i] = uf.find(i)
	}

	// For each root, store the minimum node in its set
	minNodeMap := make(map[int64]int64)
	for i := int64(1); i <= c; i++ {
		root := uf.find(i)
		if _, exists := minNodeMap[root]; !exists {
			minNodeMap[root] = i
		}
	}

	result := []int64{}

	for _, query := range queries {
		if query[0] == 1 {
			x := query[1]
			if uf.isOnline(x) {
				result = append(result, x)
			} else {
				root := uf.find(x)
				minNode, exists := minNodeMap[root]
				if exists {
					result = append(result, minNode)
				} else {
					result = append(result, -1)
				}
			}
		} else {
			x := query[1]
			uf.offline(x)
		}
	}

	return result
}
